/// <summary>
/// Extension of the <c>updateReportLineBalance</c> method.
/// </summary>
/// <remarks>
/// Used to populate additional fields in the <c>InventValueReportTmpLine</c> table
/// for the <c>ETGSPAIN</c> model.
/// </remarks>
/// <param name="_tmpReportLine">The <c>InventValueReportTmpLine</c> record.</param>
/// <param name="_sign">An integer representing the sign.</param>
/// <param name="_inventTable">The <c>InventTable</c> record.</param>
/// <param name="_inventView">The <c>InventValueReportView</c> record.</param>
protected void updateReportLineBalance(
    InventValueReportTmpLine    _tmpReportLine,
    int                         _sign,
    InventTable                 _inventTable,
    InventValueReportView       _inventView)
{
    next updateReportLineBalance(_tmpReportLine,
                                    _sign,
                                    _inventTable,
                                    _inventView);

    if (!_tmpReportLine.ETGSPAINInventLocationAdressCity
        || !_tmpReportLine.ETGSPAINPurchOperationName)
    {
        _tmpReportLine.ETGSPAINPreWriteInventValueReportTmpLine();
    }                
}

/// <summary>
