/// <param name="_tmpReportLine">The <c>InventValueReportTmpLine</c> record.</param>
/// <param name="_inventTable">The <c>InventTable</c> record.</param>
/// <param name="_inventView">The <c>InventValueReportView</c> record.</param>
protected void updateReportLineProfitLoss(
    InventValueReportTmpLine    _tmpReportLine,
    InventTable                 _inventTable,
    InventValueReportView       _inventView)
{
    next updateReportLineProfitLoss(_tmpReportLine,                                        
                                    _inventTable,
                                    _inventView);

    if (!_tmpReportLine.ETGSPAINInventLocationAdressCity
        || !_tmpReportLine.ETGSPAINPurchOperationName)
    {
        _tmpReportLine.ETGSPAINPreWriteInventValueReportTmpLine();
    }
}

/// <summary>
/// Extension of the <c>buildTransactionsWithDynamicQuery</c> method.
/// </summary>
/// <remarks>
/// Used to populate additional fields in the <c>InventValueReportTmpLine</c> table
/// for the <c>ETGSPAIN</c> model.
/// </remarks>
protected void buildTransactionsWithDynamicQuery()
{
    next buildTransactionsWithDynamicQuery();

    InventValueReportTmpLine inventValueReportTmpLine;

    ttsbegin;

    while select forupdate inventValueReportTmpLine
        where (!inventValueReportTmpLine.ETGSPAINInventLocationAdressCity
        || !inventValueReportTmpLine.ETGSPAINPurchOperationName)
    {
        inventValueReportTmpLine.ETGSPAINPreWriteInventValueReportTmpLine();
        inventValueReportTmpLine.update();
    }

    ttscommit;
}
